{"code": "import json

# Read the data from the storage
data = locals()['var_functions.query_db:5']

# Clean data - remove leading # from IDs and strip whitespace
def clean_id(id_val):
    if id_val and id_val != 'None':
        return id_val.lstrip('#').strip()
    return None

# Process transfers - each time an agent appears in oldvalue__c (and it's not 'None'), it's a transfer they initiated
transfer_counts = {}
cases_handled = {}  # track all cases each agent handled (both initial and transferred)

for record in data:
    old_agent = clean_id(record['oldvalue__c'])
    new_agent = clean_id(record['newvalue__c'])
    case_id = clean_id(record['caseid__c'])

    # Count transfers: old_agent transferred to new_agent
    if old_agent and old_agent != 'None':
        transfer_counts[old_agent] = transfer_counts.get(old_agent, 0) + 1

    # Track cases handled by both old and new agents
    if old_agent and old_agent != 'None':
        if old_agent not in cases_handled:
            cases_handled[old_agent] = set()
        cases_handled[old_agent].add(case_id)

    if new_agent and new_agent != 'None':
        if new_agent not in cases_handled:
            cases_handled[new_agent] = set()
        cases_handled[new_agent].add(case_id)

# Filter agents who handled more than 0 cases
eligible_agents = {agent: transfer_counts.get(agent, 0) for agent in cases_handled if len(cases_handled[agent]) > 0}

print('__RESULT__:')
print(json.dumps({
    'transfer_counts': transfer_counts,
    'cases_handled': {k: list(v) for k, v in cases_handled.items()},
    'eligible_agents': eligible_agents
}, indent=2))"}
